const body = $input.first().json.body;
const date = new Date(body.timestamp).toLocaleDateString('en-GB');
const html = `
<html>
<head><style>
  body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; color: #333; }
  .header { text-align: center; border-bottom: 2px solid #e91e8c; padding-bottom: 20px; margin-bottom: 30px; }
  .header h1 { color: #e91e8c; margin: 0; }
  .receipt-id { color: #888; font-size: 14px; }
  table { width: 100%; border-collapse: collapse; margin: 20px 0; }
  th { background: #f8f4ff; text-align: left; padding: 12px; font-size: 13px; color: #888; text-transform: uppercase; }
  td { padding: 12px; border-bottom: 1px solid #f0f0f0; }
  .total-row td { font-weight: 700; font-size: 18px; border-top: 2px solid #e91e8c; border-bottom: none; }
  .footer { text-align: center; margin-top: 40px; color: #aaa; font-size: 12px; }
</style></head>
<body>
  <div class="header">
    <h1>MamVibe</h1>
    <p class="receipt-id">Receipt #${body.paymentId?.substring(0, 8) || 'N/A'}</p>
    <p class="receipt-id">${date}</p>
  </div>
  <h2>Payment Receipt</h2>
  <table>
    <tr><th>Item</th><th>Amount</th></tr>
    <tr><td>${body.itemTitle}</td><td>${body.amount} BGN</td></tr>
    <tr class="total-row"><td>Total</td><td>${body.amount} BGN</td></tr>
  </table>
  <table>
    <tr><td style="color:#888;width:120px">Buyer</td><td>${body.buyerName} (${body.buyerEmail})</td></tr>
    <tr><td style="color:#888">Seller</td><td>${body.sellerName} (${body.sellerEmail})</td></tr>
    <tr><td style="color:#888">Date</td><td>${date}</td></tr>
  </table>
  <div class="footer">This is an automatically generated receipt from MamVibe.</div>
</body>
</html>`;
return [{ json: { html, buyerEmail: body.buyerEmail, buyerName: body.buyerName, itemTitle: body.itemTitle } }];
